const now = new Date().toISOString();

// 1. 獲取 AI Agent1 傳入嘅原始資料 (留意呢度係攞 .output)
const rawOutput = $input.first().json.output;

// 如果冇 output 就直接中止
if (!rawOutput) {
  return [];
}

let parsedData = {};

// 2. 清除 Markdown 標記 (```json 同 ```) 並 Parse 成 JSON 物件
try {
  // 用 Regex 移除 ```json 同 ```，然後清走頭尾空白
  const cleanJsonString = rawOutput.replace(/```json\n?|```/g, '').trim();
  // 將字串正式轉換為 JSON 物件
  parsedData = JSON.parse(cleanJsonString);
} catch (error) {
  // 如果 AI 畀嘅 JSON 格式有錯，就會入嚟呢度
  console.error("JSON 解析失敗:", error);
  return []; 
}

// 3. 檢查是否有 details 陣列 (改為檢查 parsedData)
if (!parsedData.details || !Array.isArray(parsedData.details) || parsedData.details.length === 0) {
  return [];
}

// 4. 如果有記錄，才執行 map 處理
const items = parsedData.details.map(d => ({
  summary: parsedData.summary ?? "", 
  meal_time: d.meal_time ?? "",
  food_name: d.food_name ?? "",
  food_name_en: d.food_name_en ?? "",
  main_ingredient: d.main_ingredient ?? "",
  cooking_method: d.cooking_method ?? "",
  sauce_or_seasoning: d.sauce_or_seasoning ?? "",
  style: d.style ?? "",
  calories: d.nutrition?.calories ?? "",
  protein: d.nutrition?.protein ?? "",
  fat: d.nutrition?.fat ?? "",
  carbohydrates: d.nutrition?.carbohydrates ?? "",
  fiber: d.nutrition?.fiber ?? "",
  record_date_time: now
}));

return items;

let raw = $input.first().json.output || "";

// 如果輸入已經是物件，代表已經成功解析，直接回傳
if (typeof raw === "object") {
  return [{ json: raw }];
}

// 步驟 1：嘗試從 Markdown 區塊中提取 JSON (對應新 Prompt 的 ```json ... ```)
let jsonString = raw;
const jsonMatch = raw.match(/```json\s*([\s\S]*?)\s*```/);

if (jsonMatch && jsonMatch) {
  // 如果找到 ```json 區塊，只取區塊內的內容
  jsonString = jsonMatch[1];
} else {
  // 如果沒有 ```json，嘗試找第一個 { 和最後一個 } 之間的內容
  const startIdx = raw.indexOf('{');
  const endIdx = raw.lastIndexOf('}');
  if (startIdx !== -1 && endIdx !== -1 && endIdx > startIdx) {
    jsonString = raw.substring(startIdx, endIdx + 1);
  }
}

// 步驟 2：將所有全形標點符號強制轉換為標準 JSON 支援的半形符號
jsonString = jsonString
  .replace(/：/g, ':')         
  .replace(/，/g, ',')         
  .replace(/[「」『』“”]/g, '"')
  .replace(/\n/g, '')
  .replace(/\r/g, '');

// 步驟 3：嘗試解析 JSON
let parsed;
try {
  parsed = JSON.parse(jsonString);
} catch (err1) {
  try {
    // 容錯解析
    parsed = new Function('return ' + jsonString)();
  } catch (err2) {
    // 如果解析失敗，或者用戶只是純聊天沒有觸發 JSON 生成
    // 我們回傳一個空的 details，讓後續流程不會報錯，並把 Agent 的對話保留
    return [{
      json: {
        summary: "Chat Only",
        details: [],
        agent_reply: raw, // 保留 Agent 的純文字回覆
        error: "No valid JSON found or parsing failed"
      }
    }];
  }
}

// 將 Agent 的完整回覆也塞入 parsed 物件中，方便後續 WhatsApp 回覆使用
parsed.agent_reply = raw;

return [{ json: parsed }];

// 1. 取得 AI 的完整輸出與解析結果
const aiOutput = $('Custom Code: Parse the Output from AI Agent').first().json;
let results = aiOutput.details || aiOutput['細節'] || [];

// 提取 AI 的純文字回覆
let agentReply = aiOutput.agent_reply || "";
let cleanAgentReply = agentReply.replace(/```json[\s\S]*?```/g, '').trim();

// 2. 取得 User 的真正輸入
const incoming = $('Set Variables').first().json.message || "";
const incomingLower = incoming.toLowerCase();

// 3. 語言偵測
const textForDetection = incoming.trim() ? incoming : cleanAgentReply; 
const hasHanzi = /[\u4e00-\u9fa5]/.test(textForDetection);

let language = "English";
if (hasHanzi) {
  language = "Chinese";
}

// 4. 定義餐次關鍵字 (用嚟配對 User 嘅輸入同埋 AI 嘅輸出)
const mealKeywords = {
  "breakfast": ["breakfast", "早餐", "早飯"],
  "lunch": ["lunch", "午餐", "晏晝", "午飯"],
  "afternoon tea": ["afternoon tea", "tea", "下午茶"],
  "dinner": ["dinner", "晚餐", "晚飯", "夜晚"],
  "supper": ["supper", "宵夜", "夜宵"],
  "snack": ["snack", "小食", "零食", "茶點"]
};

// 檢查 User 輸入咗咩餐次
let requestedMeals = [];
for (const [meal, keywords] of Object.entries(mealKeywords)) {
  if (keywords.some(kw => incomingLower.includes(kw))) {
    requestedMeals.push(meal);
  }
}

// 如果 User 有特別講明邊一餐，就過濾 results
if (requestedMeals.length > 0) {
  results = results.filter(result => {
    let rawMealTime = (result.meal_time || result['用餐時間'] || "").toLowerCase();

    // 搵返呢個 rawMealTime 屬於邊個標準餐次
    let standardMeal = rawMealTime;
    for (const [meal, keywords] of Object.entries(mealKeywords)) {
      if (keywords.includes(rawMealTime)) {
        standardMeal = meal;
        break;
      }
    }
    // 判斷呢個紀錄係咪 User 想要嘅餐次
    return requestedMeals.includes(standardMeal);
  });
}

// 5. 如果沒有食物記錄 (純聊天或過濾後無紀錄)，直接回覆 AI 的對話並結束
if (results.length === 0) {
  // 如果係因為過濾後無紀錄，可以畀個提示
  if (requestedMeals.length > 0 && (aiOutput.details || []).length > 0) {
      const emptyMsg = language === "Chinese" ? "找不到該餐次的紀錄。" : "No records found for the requested meal.";
      return [{ json: { language, reply: emptyMsg } }];
  }
  return [{ json: { language, reply: cleanAgentReply } }];
}

// 6. 計算營養並組合訊息
const now = new Date();
const dateOptions = { year: 'numeric', month: 'short', day: 'numeric', timeZone: 'Asia/Hong_Kong' };
const timeOptions = { hour: 'numeric', minute: '2-digit', second: '2-digit', timeZone: 'Asia/Hong_Kong' };

let labels = { calories: "Calories", fats: "Fats", protein: "Protein", carbs: "Carbs", fiber: "Fiber", total: "Total" };
let replyHeader = `Your record has been saved on ${now.toLocaleDateString('en-HK', dateOptions)} at ${now.toLocaleTimeString('en-HK', timeOptions)}.\n\nRecord Details:\n`;

const mealTimeDict = {
  "English": { "breakfast": "Breakfast", "lunch": "Lunch", "afternoon tea": "Afternoon Tea", "dinner": "Dinner", "supper": "Supper", "snack": "Snack" },
  "Chinese": { "breakfast": "早餐", "lunch": "午餐", "afternoon tea": "下午茶", "dinner": "晚餐", "supper": "宵夜", "snack": "小食" }
};

if (language === "Chinese") {
  labels = { calories: "卡路里", fats: "脂肪", protein: "蛋白質", carbs: "碳水化合物", fiber: "纖維", total: "總計" };
  replyHeader = `你嘅紀錄已經存檔在 ${now.toLocaleDateString('zh-HK', dateOptions)} ${now.toLocaleTimeString('zh-HK', timeOptions)}。\n\n紀錄內容:\n`;
}

// 如果 User 只係查詢 (例如問 "dinner?")，可以轉一轉個 Header 字眼，唔用 "saved" (存檔)
const isQuery = incomingLower.includes("?") || incomingLower.includes("？") || incomingLower.includes("咩") || incomingLower.includes("what") || incomingLower.includes("full day") || incomingLower.includes("全日");

if (isQuery) {
  replyHeader = language === "Chinese" ? `為你搵到以下紀錄：\n\n` : `Here are your requested records:\n\n`;
}

const extractNumber = (val) => {
  const num = parseFloat(String(val).replace(/[^0-9.]/g, ''));
  return isNaN(num) ? 0 : num;
};

let totalCalories = 0, totalFats = 0, totalProtein = 0, totalCarbs = 0, totalFiber = 0;
let display_details = "";

results.forEach((result) => {
  let rawMealTime = (result.meal_time || result['用餐時間'] || "unknown").toLowerCase();

  // 轉換餐次做標準英文 key，再轉做顯示語言
  let standardMealKey = rawMealTime;
  for (const [meal, keywords] of Object.entries(mealKeywords)) {
    if (keywords.includes(rawMealTime)) {
      standardMealKey = meal;
      break;
    }
  }
  let translatedMealTime = mealTimeDict[language][standardMealKey] || rawMealTime;

  const foodName = result.food_name || result['食物名稱'] || "Unknown food";
  const foodNameEn = result.food_name_english || result.food_name_en || foodName; 

  let displayFoodName = language === "English" ? foodNameEn : foodName;

  const nutrition = result.nutrition || result['營養'] || {};
  const cals = nutrition.calories || nutrition['熱量'] || 0;
  const fat = nutrition.fat || nutrition['脂肪'] || 0;
  const protein = nutrition.protein || nutrition['蛋白質'] || 0;
  const carbs = nutrition.carbohydrates || nutrition['碳水化合物'] || 0;
  const fiber = nutrition.fiber || nutrition['纖維'] || 0;

  totalCalories += extractNumber(cals);
  totalFats += extractNumber(fat);
  totalProtein += extractNumber(protein);
  totalCarbs += extractNumber(carbs);
  totalFiber += extractNumber(fiber);

  display_details += `- ${translatedMealTime}: ${displayFoodName} (${labels.calories}: ${cals} kcal, ${labels.fats}: ${fat}g, ${labels.protein}: ${protein}g, ${labels.carbs}: ${carbs}g, ${labels.fiber}: ${fiber}g)\n`;
});

const formatNum = (num) => parseFloat(num.toFixed(1));

const finalCal = formatNum(totalCalories);
const finalFats = formatNum(totalFats);
const finalProtein = formatNum(totalProtein);
const finalCarbs = formatNum(totalCarbs);
const finalFiber = formatNum(totalFiber);

display_details += `\n- ${labels.total}: (${labels.calories}: ${finalCal} kcal, ${labels.fats}: ${finalFats}g, ${labels.protein}: ${finalProtein}g, ${labels.carbs}: ${finalCarbs}g, ${labels.fiber}: ${finalFiber}g)\n`;

const finalReply = replyHeader + display_details;

return [{ json: { language, reply: finalReply } }];
